      out.write("			$(document).on(\"keydown\", \"input\", function (e) {\r\n");
      out.write("				  const $currentInput = $(this);\r\n");
      out.write("				  const $currentTd = $currentInput.closest(\"td\");\r\n");
      out.write("				  const colIndex = $currentTd.index();\r\n");
      out.write("				  const $currentTr = $currentInput.closest(\"tr\");\r\n");
      out.write("\r\n");
      out.write("				  let $targetInput;\r\n");
      out.write("\r\n");
      out.write("				  if (e.key === \"ArrowUp\") {\r\n");
      out.write("				    const $targetTr = $currentTr.prev(\"tr\");\r\n");
      out.write("				    $targetInput = $targetTr.find(\"td\").eq(colIndex).find(\"input\").click();\r\n");
      out.write("				    $(this).select();\r\n");
      out.write("				  } else if (e.key === \"ArrowDown\") {\r\n");
      out.write("				    const $targetTr = $currentTr.next(\"tr\");\r\n");
      out.write("				    $targetInput = $targetTr.find(\"td\").eq(colIndex).find(\"input\").click();\r\n");
      out.write("				    $(this).select();\r\n");
      out.write("				  } else if (e.key === \"ArrowLeft\") {\r\n");
      out.write("				    const $tds = $currentTr.find(\"td\");\r\n");
      out.write("				    if (colIndex > 0) {\r\n");
      out.write("				      $targetInput = $tds.eq(colIndex - 1).find(\"input\").click();\r\n");
